from flask import Flask, request, session, redirect, url_for, render_template_string
import xml.etree.ElementTree as ET
from datetime import datetime
import base64
import hashlib
import os

app = Flask(__name__)
app.secret_key = os.urandom(24)

SAML_NAMESPACES = {
    'saml': 'urn:oasis:names:tc:SAML:2.0:assertion',
    'samlp': 'urn:oasis:names:tc:SAML:2.0:protocol',
    'xs': 'http://www.w3.org/2001/XMLSchema',
    'xsi': 'http://www.w3.org/2001/XMLSchema-instance'
}

def parse_saml_response(saml_response):
    try:
        decoded_xml = base64.b64decode(saml_response)
        root = ET.fromstring(decoded_xml)
        
        # Validate SAML Response structure
        response_element = root.find('.//samlp:Response', namespaces=SAML_NAMESPACES)
        if response_element is None:
            raise ValueError("SAML Response element not found")
        
        # Check if assertions are present
        assertions = root.findall('.//saml:Assertion', namespaces=SAML_NAMESPACES)
        if not assertions:
            raise ValueError("No assertions found in SAML response")
        
        # Extract user attributes from first assertion
        assertion = assertions[0]
        user_attributes = extract_user_attributes(assertion)
        
        # Validate assertion
        validate_assertion(assertion)
        
        return user_attributes
        
    except Exception as e:
        raise ValueError(f"Failed to parse SAML response: {str(e)}")

def extract_user_attributes(assertion):
    attributes = {}
    
    # Extract subject (user identifier)
    subject = assertion.find('.//saml:Subject', namespaces=SAML_NAMESPACES)
    if subject is not None:
        name_id = subject.find('.//saml:NameID', namespaces=SAML_NAMESPACES)
        if name_id is not None:
            attributes['user_id'] = name_id.text
            
    # Extract attribute statements
    attribute_statements = assertion.findall('.//saml:AttributeStatement', namespaces=SAML_NAMESPACES)
    for attr_stmt in attribute_statements:
        attributes_from_stmt = extract_attributes_from_statement(attr_stmt)
        attributes.update(attributes_from_stmt)
    
    return attributes

def extract_attributes_from_statement(attribute_statement):
    attributes = {}
    for attr in attribute_statement.findall('.//saml:Attribute', namespaces=SAML_NAMESPACES):
        attr_name = attr.get('Name')
        attr_values = attr.findall('.//saml:AttributeValue', namespaces=SAML_NAMESPACES)
        if attr_values:
            attributes[attr_name] = [val.text for val in attr_values]
    
    return attributes

def validate_assertion(assertion):
    # Check assertion validity period
    conditions = assertion.find('.//saml:Conditions', namespaces=SAML_NAMESPACES)
    if conditions is not None:
        not_before = conditions.get('NotBefore')
        not_on_or_after = conditions.get('NotOnOrAfter')
        
        if not_before:
            not_before_time = datetime.fromisoformat(not_before.replace('Z', '+00:00'))
            if datetime.now() < not_before_time:
                raise ValueError("Assertion not yet valid")
                
        if not_on_or_after:
            not_on_or_after_time = datetime.fromisoformat(not_on_or_after.replace('Z', '+00:00'))
            if datetime.now() > not_on_or_after_time:
                raise ValueError("Assertion expired")

@app.route('/saml/acs', methods=['POST'])
def saml_acs():
    try:
        saml_response = request.form.get('SAMLResponse')
        if not saml_response:
            return "Missing SAMLResponse", 400
            
        # Parse and validate SAML response
        user_attributes = parse_saml_response(saml_response)
        
        # Create user session
        session['user_attributes'] = user_attributes
        session['authenticated'] = True
        
        # Redirect to protected resource or dashboard
        return redirect(url_for('dashboard'))
        
    except ValueError as e:
        return f"Authentication failed: {str(e)}", 401
    except Exception as e:
        return f"Error processing SAML response: {str(e)}", 500

@app.route('/dashboard')
def dashboard():
    if not session.get('authenticated'):
        return redirect(url_for('login'))
    
    user_attrs = session.get('user_attributes', {})
    return render_template_string('''
        <h1>Dashboard</h1>
        <p>Welcome, {{ user_id }}!</p>
        <h2>User Attributes:</h2>
        <ul>
        {% for key, value in user_attrs.items() %}
            <li><strong>{{ key }}:</strong> {{ value }}</li>
        {% endfor %}
        </ul>
        <a href="/logout">Logout</a>
    ''', user_id=user_attrs.get('user_id', 'Unknown'), user_attrs=user_attrs)

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('login'))

@app.route('/login')
def login():
    return render_template_string('''
        <h1>SSO Login</h1>
        <p>Redirect to your SAML Identity Provider to authenticate</p>
    ''')

